// MARK: - Deep Link Navigator

class DeepLinkNavigator {
    
    static let shared = DeepLinkNavigator()
    
    private init() {}
    
    // Track the source of deep link for analytics
    enum LinkSource: String {
        case marketingCampaign = "utm_campaign"
        case emailNotification = "email"
        case pushNotification = "push"
        case unknown = "unknown"
    }
    
    func detectSource(from url: URL) -> LinkSource {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .unknown
        }
        
        let queryItems = components.queryItems ?? []
        
        if queryItems.contains(where: { $0.name == "utm_campaign" }) {
            return .marketingCampaign
        } else if queryItems.contains(where: { $0.name == "source" && $0.value == "email" }) {
            return .emailNotification
        } else if queryItems.contains(where: { $0.name == "source" && $0.value == "push" }) {
            return .pushNotification
        }
        
        return .unknown
    }
    
    func navigate(to route: DeepLinkRoute, from source: LinkSource = .unknown) {
        guard let rootViewController = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .first?.windows
            .first(where: { $0.isKeyWindow })?.rootViewController else {
            // Store the route for deferred navigation
            pendingRoute = route
            pendingSource = source
            return
        }
        
        logDeepLinkEvent(route: route, source: source)
        
        let navigationController: UINavigationController
        
        if let navController = rootViewController as? UINavigationController {
            navigationController = navController
        } else if let tabBarController = rootViewController as? UITabBarController,
                  let navController = tabBarController.selectedViewController as? UINavigationController {
            navigationController = navController
        } else {
            // Wrap in navigation controller if needed
            let navController = UINavigationController(rootViewController: rootViewController)
            navigationController = navController
            return
        }
        
        let destinationVC = viewController(for: route)
        
        DispatchQueue.main.async {
            navigationController.pushViewController(destinationVC, animated: true)
        }
    }
    
    func viewController(for route: DeepLinkRoute) -> UIViewController {
        switch route {
        case .profile(let userID):
            let vc = ProfileViewController()
            vc.userID = userID
            return vc
            
        case .paymentConfirm(let transactionID):
            let vc = PaymentConfirmViewController()
            vc.transactionID = transactionID
            return vc
            
        case .adminSettings:
            let vc = AdminSettingsViewController()
            return vc
            
        case .unknown:
            let vc = UIViewController()
            vc.view.backgroundColor = .systemBackground
            vc.title = "Page Not Found"
            return vc
        }
    }
    
    // MARK: - Deferred Navigation (for cold launches)
    
    private var pendingRoute: DeepLinkRoute?
    private var pendingSource: LinkSource?
    
    func handlePendingNavigation() {
        guard let route = pendingRoute else { return }
        let source = pendingSource ?? .unknown
        pendingRoute = nil
        pendingSource = nil
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
            self?.navigate(to: route, from: source)
        }
    }
    
    // MARK: - Analytics Logging
    
    private func logDeepLinkEvent(route: DeepLinkRoute, source: LinkSource) {
        print("[DeepLink Analytics] Route: \(route.description), Source: \(source.rawValue)")
        // Integrate with your analytics service here
        // e.g., Analytics.logEvent("deep_link_opened", parameters: [...])
    }
}

// MARK: - SceneDelegate with Universal Link Handling

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let rootVC = UIViewController()
        rootVC.view.backgroundColor = .systemBackground
        rootVC.title = "Home"
        
        let navigationController = UINavigationController(rootViewController: rootVC)
        window.rootViewController = navigationController
        window.makeKeyAndVisible()
        self.window = window
        
        // Handle universal link from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleUniversalLink(url: urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleUniversalLink(url: url)
        }
        
        // Handle any pending navigation from app delegate
        DeepLinkNavigator.shared.handlePendingNavigation()
    }
    
    // Handle universal links when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        handleUniversalLink(url: url)
    }
    
    // Handle URL scheme deep links
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleUniversalLink(url: url)
    }
    
    private func handleUniversalLink(url: URL) {
        let route = UniversalLinkParser.parse(url: url)
        let source = DeepLinkNavigator.shared.detectSource(from: url)
        
        guard case .unknown = route else {
            DeepLinkNavigator.shared.navigate(to: route, from: source)
            return
        }
        
        // For unknown routes, optionally open in Safari
        print("[DeepLink] Unknown route for URL: \(url.absoluteString)")
    }
}

